import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface UploadedFile {
  id: string;
  name: string;
  type: string;
  data: string; // Base64 string
  size: number;
}

export interface Template {
  id: string;
  name: string;
  description: string;
  structure: string;
}

export interface GenerationConfig {
  tone: 'strict' | 'polite' | 'summary';
  detailLevel: 'high' | 'medium' | 'low';
}

export type ProcessingStatus = 'idle' | 'uploading' | 'analyzing' | 'generating' | 'completed' | 'error';

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { UploadedFile } from "../types";
import { SYSTEM_INSTRUCTION } from "../constants";

export const generateReport = async (
  apiKey: string,
  textInput: string,
  files: UploadedFile[],
  templateStructure: string
): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Determine model based on complexity. Using Pro for better reasoning on official documents.
  const modelName = 'gemini-3-pro-preview'; 

  const fileParts = files.map(file => {
    // Determine mime type. The API needs standard MIME types.
    // Base64 data in UploadedFile should be stripped of the header (data:image/png;base64,) if present,
    // but the API usually expects raw base64 data in inlineData.
    const base64Data = file.data.includes('base64,') 
      ? file.data.split('base64,')[1] 
      : file.data;

    return {
      inlineData: {
        mimeType: file.type,
        data: base64Data
      }
    };
  });

  const prompt = `
[사용자 입력 데이터]
${textInput}

[작성 요청 서식]
${templateStructure}

위 [사용자 입력 데이터]와 첨부된 파일들을 분석하여, [작성 요청 서식]에 맞춰 공문서를 작성해 주십시오. 
시스템 지시사항(페르소나, 문체, 형식)을 반드시 준수하십시오.
`;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelName,
      contents: {
        role: 'user',
        parts: [
          { text: prompt },
          ...fileParts
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.2, // Low temperature for factual, consistent output
      }
    });

    return response.text || "문서를 생성할 수 없습니다. 다시 시도해 주세요.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useCallback } from 'react';
import { UploadedFile } from '../types';

interface FileUploadProps {
  files: UploadedFile[];
  onFilesChange: (files: UploadedFile[]) => void;
}

export const FileUpload: React.FC<FileUploadProps> = ({ files, onFilesChange }) => {
  const handleFileChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files) {
      const newFiles: UploadedFile[] = [];
      const fileList = Array.from(event.target.files);

      fileList.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          newFiles.push({
            id: Math.random().toString(36).substring(7),
            name: file.name,
            type: file.type,
            data: reader.result as string,
            size: file.size
          });

          if (newFiles.length === fileList.length) {
            onFilesChange([...files, ...newFiles]);
          }
        };
        reader.readAsDataURL(file);
      });
    }
  }, [files, onFilesChange]);

  const removeFile = (id: string) => {
    onFilesChange(files.filter(f => f.id !== id));
  };

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-center w-full">
        <label htmlFor="dropzone-file" className="flex flex-col items-center justify-center w-full h-32 border-2 border-admin-300 border-dashed rounded-lg cursor-pointer bg-admin-50 hover:bg-admin-100 transition-colors">
          <div className="flex flex-col items-center justify-center pt-5 pb-6">
            <svg className="w-8 h-8 mb-4 text-admin-500" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
              <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
            </svg>
            <p className="mb-2 text-sm text-admin-700"><span className="font-semibold">클릭하여 업로드</span> 또는 파일을 여기로 드래그</p>
            <p className="text-xs text-admin-500">PDF, PNG, JPG (최대 10MB)</p>
          </div>
          <input 
            id="dropzone-file" 
            type="file" 
            className="hidden" 
            multiple 
            accept="application/pdf,image/png,image/jpeg,image/webp"
            onChange={handleFileChange}
          />
        </label>
      </div>

      {files.length > 0 && (
        <ul className="grid grid-cols-1 gap-2">
          {files.map((file) => (
            <li key={file.id} className="flex items-center justify-between p-2 bg-white border border-admin-200 rounded shadow-sm">
              <div className="flex items-center overflow-hidden">
                <span className="bg-admin-100 text-admin-800 text-xs font-medium mr-2 px-2.5 py-0.5 rounded uppercase">{file.type.split('/')[1]}</span>
                <span className="text-sm text-gray-700 truncate max-w-xs">{file.name}</span>
              </div>
              <button 
                onClick={() => removeFile(file.id)}
                className="text-red-500 hover:text-red-700 text-sm font-medium px-2"
              >
                삭제
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

import React from 'react';

interface DocumentEditorProps {
