              </h2>
              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-600">파일 업로드 (참고자료)</label>
                  <FileUpload files={inputFiles} onFilesChange={setInputFiles} />
