                  <label className="text-sm font-semibold text-gray-600">텍스트 / 메모 / 링크</label>
                  <DocumentEditor 
                    label="" 
                    value={inputText} 
                    onChange={setInputText} 
                    placeholder="보도자료 초안, 회의 메모, 주요 수치 등을 자유롭게 입력하세요."
